// Extrair evento do webhook Asaas
const body = $input.first().json.body || $input.first().json;

const event = body.event;
const payment = body.payment || {};

// Mapear status do Asaas para status interno
const statusMap = {
  'PAYMENT_CONFIRMED': 'aprovado',
  'PAYMENT_RECEIVED': 'aprovado',
  'PAYMENT_OVERDUE': 'vencido',
  'PAYMENT_DELETED': 'cancelado',
  'PAYMENT_REFUNDED': 'estornado',
  'PAYMENT_CHARGEBACK_REQUESTED': 'chargeback',
  'PAYMENT_CHARGEBACK_DISPUTE': 'chargeback',
  'PAYMENT_AWAITING_CHARGEBACK_REVERSAL': 'chargeback',
  'PAYMENT_DUNNING_RECEIVED': 'aprovado',
  'PAYMENT_DUNNING_REQUESTED': 'cobranca_enviada',
  'PAYMENT_CREATED': 'pendente',
  'PAYMENT_UPDATED': 'pendente'
};

const statusInterno = statusMap[event] || 'desconhecido';
const isAprovado = ['PAYMENT_CONFIRMED', 'PAYMENT_RECEIVED'].includes(event);
const isNegativo = ['PAYMENT_OVERDUE', 'PAYMENT_DELETED', 'PAYMENT_REFUNDED', 'PAYMENT_CHARGEBACK_REQUESTED'].includes(event);

return [{
  json: {
    event,
    paymentId: payment.id,
    statusInterno,
    isAprovado,
    isNegativo,
    value: payment.value,
    billingType: payment.billingType,
    customerName: payment.customer || '',
    paidAt: payment.confirmedDate || payment.paymentDate || null
  }
}];

// Buscar dados do lead vinculado ao pedido para enviar WhatsApp
const evento = $('Extrair Evento').first().json;
const pedidoData = $('Atualizar Pedido').first().json;
const pedido = Array.isArray(pedidoData) ? pedidoData[0] : pedidoData;

return [{
  json: {
    ...evento,
    lead_id: pedido ? pedido.lead_id : null,
    plano: pedido ? pedido.plano : '',
    pedido_id: pedido ? pedido.id : null
  }
}];

// WhatsApp - Pagamento Aprovado
const evento = $('Preparar Notificação').first().json;
const leadData = $('Buscar Lead').first().json;
const lead = Array.isArray(leadData) ? leadData[0] : leadData;

if (!lead || !lead.whatsapp) {
  return [{ json: { skip: true, reason: 'Lead sem WhatsApp' } }];
}

const numero = lead.whatsapp.replace(/\D/g, '');
const nome = lead.nome || 'Cliente';
const plano = evento.plano || 'seu tratamento';

const mensagem = `Oi, ${nome}, tudo bem?\nSeja bem-vindo(a) à Maori Saúde! 🎉\n\nRecebemos a confirmação do pagamento do ${plano}.\n\nNosso time médico já está preparando tudo para iniciar seu acompanhamento.\n\nEm breve entraremos em contato com os próximos passos!`;

return [{
  json: {
    number: `55${numero}`,
    options: { delay: 1200, presence: 'composing' },
    textMessage: { text: mensagem }
  }
}];

// WhatsApp - Problema no Pagamento
const evento = $('Preparar Notificação').first().json;
const leadData = $('Buscar Lead').first().json;
const lead = Array.isArray(leadData) ? leadData[0] : leadData;

if (!lead || !lead.whatsapp) {
  return [{ json: { skip: true, reason: 'Lead sem WhatsApp' } }];
}

const numero = lead.whatsapp.replace(/\D/g, '');
const nome = lead.nome || 'Cliente';

const statusMsg = {
  'vencido': 'identificamos que o pagamento não foi realizado dentro do prazo',
  'estornado': 'o pagamento foi estornado',
  'cancelado': 'o pagamento foi cancelado',
  'chargeback': 'recebemos uma contestação referente ao pagamento'
};

const detalhe = statusMsg[evento.statusInterno] || 'houve um problema com seu pagamento';

const mensagem = `Oi, ${nome}!\n\nPassando para informar que ${detalhe}.\n\nSe precisar de ajuda ou quiser tentar novamente, estamos à disposição aqui pelo WhatsApp.\n\nEquipe Maori Saúde`;

return [{
  json: {
    number: `55${numero}`,
    options: { delay: 1200, presence: 'composing' },
    textMessage: { text: mensagem }
  }
}];
